window.BILARA["dn24"] = window.BILARA["dn24"] || {};
window.BILARA["dn24"]["vi"] = {
  "dn24:0.1": "Trường Bộ Kinh 24 ",
  "dn24:0.2": "Kinh Pāthika ",
  "dn24:1.0": "1. Chuyện Sunakkhatta ",
  "dn24:1.1.1": "Tôi nghe như vầy",
  "dn24:1.1.2": "Một thời, Đức Thế Tôn ngự tại xứ Malla, ở một thị trấn của người Malla tên là Anupiya. ",
  "dn24:1.1.3": "Rồi vào buổi sáng, Đức Thế Tôn đắp y, mang y bát, vào làng Anupiya khất thực. ",
  "dn24:1.1.4": "Khi ấy, Đức Thế Tôn nghĩ: ",
  "dn24:1.1.5": "“Còn quá sớm để đi khất thực ở Anupiya. ",
  "dn24:1.1.6": "Ta hãy đến khu vườn của du sĩ Bhaggavagotta, đến chỗ du sĩ Bhaggavagotta.” ",
  "dn24:1.2.1": "Rồi Đức Thế Tôn đi đến khu vườn của du sĩ Bhaggavagotta, đến chỗ du sĩ Bhaggavagotta. ",
  "dn24:1.2.2": "Du sĩ Bhaggavagotta bạch Đức Thế Tôn: ",
  "dn24:1.2.3": "“Xin kính mời Đức Thế Tôn đến đây. ",
  "dn24:1.2.4": "Con xin chào mừng Đức Thế Tôn. ",
  "dn24:1.2.5": "Bạch Thế Tôn, đã lâu rồi Đức Thế Tôn mới có dịp đến đây. ",
  "dn24:1.2.6": "Xin Đức Thế Tôn ngồi xuống, đây là chỗ ngồi đã chuẩn bị sẵn.” ",
  "dn24:1.2.7": "Đức Thế Tôn ngồi xuống chỗ đã chuẩn bị. ",
  "dn24:1.2.8": "Du sĩ Bhaggavagotta cũng lấy một chỗ ngồi thấp và ngồi xuống một bên. ",
  "dn24:1.2.9": "Ngồi một bên rồi, du sĩ Bhaggavagotta bạch Đức Thế Tôn: ",
  "dn24:1.2.10": "“Bạch Thế Tôn, cách đây không lâu, Sunakkhatta, con trai dòng Licchavi, đã đến chỗ con; đến nơi, anh ta nói với con: ",
  "dn24:1.2.11": "‘Này Bhaggava, tôi đã từ bỏ Đức Thế Tôn. ",
  "dn24:1.2.12": "Tôi không còn sống dưới sự hướng dẫn của Đức Thế Tôn nữa.’ ",
  "dn24:1.2.13": "Bạch Thế Tôn, có đúng như vậy chăng, như Sunakkhatta, con trai dòng Licchavi, đã nói?” ",
  "dn24:1.2.14": "“Đúng vậy, này Bhaggava, như Sunakkhatta, con trai dòng Licchavi, đã nói. ",
  "dn24:1.3.1": "Này Bhaggava, cách đây không lâu, Sunakkhatta, con trai dòng Licchavi, đã đến chỗ Ta; đến nơi, đảnh lễ Ta rồi ngồi xuống một bên. Ngồi một bên rồi, này Bhaggava, Sunakkhatta, con trai dòng Licchavi, nói với Ta: ",
  "dn24:1.3.2": "‘Bạch Thế Tôn, nay con từ bỏ Đức Thế Tôn. ",
  "dn24:1.3.3": "Bạch Thế Tôn, con không còn sống dưới sự hướng dẫn của Đức Thế Tôn nữa.’ ",
  "dn24:1.3.4": "Khi nghe vậy, này Bhaggava, Ta nói với Sunakkhatta, con trai dòng Licchavi: ",
  "dn24:1.3.5": "‘Này Sunakkhatta, Ta có từng nói với ngươi rằng: ",
  "dn24:1.3.6": "Hãy đến, này Sunakkhatta, hãy sống dưới sự hướng dẫn của Ta không?’ ",
  "dn24:1.3.7": "‘Thưa không, bạch Thế Tôn.’ ",
  "dn24:1.3.8": "‘Hay ngươi đã nói với Ta rằng—",
  "dn24:1.3.9": "Bạch Thế Tôn, con sẽ sống dưới sự hướng dẫn của Đức Thế Tôn?’ ",
  "dn24:1.3.10": "‘Thưa không, bạch Thế Tôn.’ ",
  "dn24:1.3.11": "‘Vậy thì, này Sunakkhatta, Ta chưa từng nói với ngươi—",
  "dn24:1.3.12": "Hãy đến, này Sunakkhatta, hãy sống dưới sự hướng dẫn của Ta. ",
  "dn24:1.3.13": "Và ngươi cũng chưa từng nói với Ta—",
  "dn24:1.3.14": "Bạch Thế Tôn, con sẽ sống dưới sự hướng dẫn của Đức Thế Tôn. ",
  "dn24:1.3.15": "Vậy thì, này kẻ ngu si, ngươi là ai mà từ bỏ ai? ",
  "dn24:1.3.16": "Hãy xem, này kẻ ngu si, lỗi của ngươi lớn biết bao.’ ",
  "dn24:1.4.1": "‘Bạch Thế Tôn, nhưng Đức Thế Tôn không biểu diễn thần thông vượt quá pháp người thường cho con.’ ",
  "dn24:1.4.2": "‘Này Sunakkhatta, Ta có từng nói với ngươi rằng—",
  "dn24:1.4.3": "Hãy đến, này Sunakkhatta, hãy sống dưới sự hướng dẫn của Ta, Ta sẽ biểu diễn thần thông vượt quá pháp người thường cho ngươi không?’ ",
  "dn24:1.4.4": "‘Thưa không, bạch Thế Tôn.’ ",
  "dn24:1.4.5": "‘Hay ngươi đã nói với Ta rằng—",
  "dn24:1.4.6": "Bạch Thế Tôn, con sẽ sống dưới sự hướng dẫn của Đức Thế Tôn, Đức Thế Tôn sẽ biểu diễn thần thông vượt quá pháp người thường cho con không?’ ",
  "dn24:1.4.7": "‘Thưa không, bạch Thế Tôn.’ ",
  "dn24:1.4.8": "‘Vậy thì, này Sunakkhatta, Ta chưa từng nói với ngươi—",
  "dn24:1.4.9": "Hãy đến, này Sunakkhatta, hãy sống dưới sự hướng dẫn của Ta, Ta sẽ biểu diễn thần thông vượt quá pháp người thường cho ngươi; ",
  "dn24:1.4.10": "và ngươi cũng chưa từng nói với Ta—",
  "dn24:1.4.11": "Bạch Thế Tôn, con sẽ sống dưới sự hướng dẫn của Đức Thế Tôn, Đức Thế Tôn sẽ biểu diễn thần thông vượt quá pháp người thường cho con. ",
  "dn24:1.4.12": "Vậy thì, này kẻ ngu si, ngươi là ai mà từ bỏ ai? ",
  "dn24:1.4.13": "Ngươi nghĩ sao, này Sunakkhatta, ",
  "dn24:1.4.14": "dù thần thông vượt quá pháp người thường có được biểu diễn hay không được biểu diễn, Pháp mà Ta giảng dạy có đưa người hành trì đến sự đoạn tận khổ đau chân chánh không?’ ",
  "dn24:1.4.15": "‘Bạch Thế Tôn, dù thần thông vượt quá pháp người thường có được biểu diễn hay không được biểu diễn, Pháp mà Đức Thế Tôn giảng dạy đưa người hành trì đến sự đoạn tận khổ đau chân chánh.’ ",
  "dn24:1.4.16": "‘Vậy thì, này Sunakkhatta, dù thần thông vượt quá pháp người thường có được biểu diễn hay không được biểu diễn, Pháp mà Ta giảng dạy đưa người hành trì đến sự đoạn tận khổ đau chân chánh. ",
  "dn24:1.4.17": "Vậy, này Sunakkhatta, việc biểu diễn thần thông vượt quá pháp người thường có ích lợi gì? ",
  "dn24:1.4.18": "Hãy xem, này kẻ ngu si, lỗi của ngươi lớn biết bao.’ ",
  "dn24:1.5.1": "‘Bạch Thế Tôn, nhưng Đức Thế Tôn không trình bày về nguồn gốc của thế giới cho con.’ ",
  "dn24:1.5.2": "‘Này Sunakkhatta, Ta có từng nói với ngươi rằng—",
  "dn24:1.5.3": "Hãy đến, này Sunakkhatta, hãy sống dưới sự hướng dẫn của Ta, Ta sẽ trình bày về nguồn gốc của thế giới cho ngươi không?’ ",
  "dn24:1.5.4": "‘Thưa không, bạch Thế Tôn.’ ",
  "dn24:1.5.5": "‘Hay ngươi đã nói với Ta rằng—",
  "dn24:1.5.6": "Bạch Thế Tôn, con sẽ sống dưới sự hướng dẫn của Đức Thế Tôn, Đức Thế Tôn sẽ trình bày về nguồn gốc của thế giới cho con không?’ ",
  "dn24:1.5.7": "‘Thưa không, bạch Thế Tôn.’ ",
  "dn24:1.5.8": "‘Vậy thì, này Sunakkhatta, Ta chưa từng nói với ngươi—",
  "dn24:1.5.9": "Hãy đến, này Sunakkhatta, hãy sống dưới sự hướng dẫn của Ta, Ta sẽ trình bày về nguồn gốc của thế giới cho ngươi. ",
  "dn24:1.5.10": "Và ngươi cũng chưa từng nói với Ta—",
  "dn24:1.5.11": "Bạch Thế Tôn, con sẽ sống dưới sự hướng dẫn của Đức Thế Tôn, Đức Thế Tôn sẽ trình bày về nguồn gốc của thế giới cho con. ",
  "dn24:1.5.12": "Vậy thì, này kẻ ngu si, ngươi là ai mà từ bỏ ai? ",
  "dn24:1.5.13": "Ngươi nghĩ sao, này Sunakkhatta, ",
  "dn24:1.5.14": "dù nguồn gốc của thế giới có được trình bày hay không được trình bày, Pháp mà Ta giảng dạy có đưa người hành trì đến sự đoạn tận khổ đau chân chánh không?’ ",
  "dn24:1.5.15": "‘Bạch Thế Tôn, dù nguồn gốc của thế giới có được trình bày hay không được trình bày, Pháp mà Đức Thế Tôn giảng dạy đưa người hành trì đến sự đoạn tận khổ đau chân chánh.’ ",
  "dn24:1.5.16": "‘Vậy thì, này Sunakkhatta, dù nguồn gốc của thế giới có được trình bày hay không được trình bày, Pháp mà Ta giảng dạy đưa người hành trì đến sự đoạn tận khổ đau chân chánh. ",
  "dn24:1.5.17": "Vậy, này Sunakkhatta, việc trình bày về nguồn gốc của thế giới có ích lợi gì? ",
  "dn24:1.5.18": "Hãy xem, này kẻ ngu si, lỗi của ngươi lớn biết bao. ",
  "dn24:1.6.1": "Này Sunakkhatta, bằng nhiều cách ngươi đã ca ngợi Ta ở làng Vajji—",
  "dn24:1.6.2": "Đức Thế Tôn là bậc A-la-hán, Chánh Đẳng Giác, Minh Hạnh Túc, Thiện Thệ, Thế Gian Giải, Vô Thượng Sĩ Điều Ngự Trượng Phu, Thiên Nhân Sư, Phật, Thế Tôn. ",
  "dn24:1.6.3": "Như vậy, này Sunakkhatta, ngươi đã ca ngợi Ta bằng nhiều cách ở làng Vajji. ",
  "dn24:1.6.4": "Này Sunakkhatta, bằng nhiều cách ngươi đã ca ngợi Chánh Pháp ở làng Vajji—",
  "dn24:1.6.5": "Chánh Pháp đã được Đức Thế Tôn khéo giảng, thiết thực hiện tiền, không phụ thuộc thời gian, đến để mà thấy, có khả năng dẫn dắt, để người trí tự mình chứng nghiệm. ",
  "dn24:1.6.6": "Như vậy, này Sunakkhatta, ngươi đã ca ngợi Chánh Pháp bằng nhiều cách ở làng Vajji. ",
  "dn24:1.6.7": "Này Sunakkhatta, bằng nhiều cách ngươi đã ca ngợi Tăng đoàn ở làng Vajji—",
  "dn24:1.6.8": "Tăng đoàn đệ tử của Đức Thế Tôn là bậc thiện hạnh, chánh hạnh, trí hạnh, chính đáng hạnh; đó là bốn đôi tám vị, đây là Tăng đoàn đệ tử của Đức Thế Tôn, đáng được cúng dường, đáng được đón tiếp, đáng được dâng tặng, đáng được chắp tay, là phước điền vô thượng cho đời. ",
  "dn24:1.6.9": "Như vậy, này Sunakkhatta, ngươi đã ca ngợi Tăng đoàn bằng nhiều cách ở làng Vajji. ",
  "dn24:1.6.10": "Này Sunakkhatta, Ta báo cho ngươi biết, Ta thông báo cho ngươi biết. ",
  "dn24:1.6.11": "Này Sunakkhatta, sẽ có người nói về ngươi rằng: Sunakkhatta, con trai dòng Licchavi, không thể sống phạm hạnh dưới sự chỉ dẫn của Sa-môn Gotama, không đủ sức, đã từ bỏ học giới và quay về đời sống thấp kém. ",
  "dn24:1.6.12": "Như vậy, này Sunakkhatta, sẽ có người nói về ngươi.’ ",
  "dn24:1.6.13": "Như vậy, này Bhaggava, dù được Ta nói, Sunakkhatta, con trai dòng Licchavi, vẫn từ bỏ Pháp và Luật này, như kẻ đã định đọa vào địa ngục. ",
  "dn24:1.7.0": "2. Chuyện Korakkhattiya ",
  "dn24:1.7.1": "Này Bhaggava, có một lần Ta đang ở xứ Thūlū, tại một thị trấn của người Thūlū tên là Uttarakā. ",
  "dn24:1.7.2": "Rồi vào buổi sáng, này Bhaggava, Ta đắp y, mang y bát, cùng với Sunakkhatta, con trai dòng Licchavi, làm Sa-môn đi theo hầu, vào làng Uttarakā khất thực. ",
  "dn24:1.7.3": "Lúc bấy giờ, có một du sĩ lõa thể tên Korakkhattiya giữ giới bắt chước chó, đi bằng bốn chi, nhai và ăn thức ăn rải trên mặt đất chỉ bằng miệng. ",
  "dn24:1.7.4": "Này Bhaggava, Sunakkhatta, con trai dòng Licchavi, thấy du sĩ lõa thể Korakkhattiya giữ giới bắt chước chó, đi bằng bốn chi, nhai và ăn thức ăn rải trên mặt đất chỉ bằng miệng. ",
  "dn24:1.7.5": "Thấy vậy, anh ta nghĩ: ",
  "dn24:1.7.6": "‘Thật lành thay, Sa-môn này là người tốt, đi bằng bốn chi, nhai và ăn thức ăn rải trên mặt đất chỉ bằng miệng.’ ",
  "dn24:1.7.7": "Này Bhaggava, Ta đọc được tâm ý của Sunakkhatta, con trai dòng Licchavi, bằng tâm mình, rồi bảo Sunakkhatta, con trai dòng Licchavi: ",
  "dn24:1.7.8": "‘Này kẻ ngu si, ngươi vẫn còn tự xưng là Sa-môn, đệ tử dòng Thích-ca sao?’ ",
  "dn24:1.7.9": "‘Bạch Thế Tôn, tại sao Đức Thế Tôn lại nói với con như vầy: ",
  "dn24:1.7.10": "“Này kẻ ngu si, ngươi vẫn còn tự xưng là Sa-môn, đệ tử dòng Thích-ca sao?”’ ",
  "dn24:1.7.11": "‘Này Sunakkhatta, chẳng phải khi thấy du sĩ lõa thể Korakkhattiya giữ giới bắt chước chó, đi bằng bốn chi, nhai và ăn thức ăn rải trên mặt đất chỉ bằng miệng, ngươi đã nghĩ—",
  "dn24:1.7.12": "Thật lành thay, Sa-môn này là người tốt, đi bằng bốn chi, nhai và ăn thức ăn rải trên mặt đất chỉ bằng miệng?’ ",
  "dn24:1.7.13": "‘Thưa vâng, bạch Thế Tôn. ",
  "dn24:1.7.14": "Nhưng bạch Thế Tôn, tại sao Đức Thế Tôn lại keo kiệt với quả A-la-hán?’ ",
  "dn24:1.7.15": "‘Này kẻ ngu si, Ta không keo kiệt với quả A-la-hán. ",
  "dn24:1.7.16": "Tà kiến xấu này chỉ khởi lên nơi ngươi, hãy từ bỏ nó. ",
  "dn24:1.7.17": "Đừng để nó gây ra đau khổ và bất lợi cho ngươi lâu dài. ",
  "dn24:1.7.18": "Này Sunakkhatta, ngươi nghĩ rằng du sĩ lõa thể Korakkhattiya – Sa-môn này là người tốt. Bảy ngày nữa ông ta sẽ chết vì bội thực. ",
  "dn24:1.7.19": "Chết rồi, ông ta sẽ tái sinh vào cõi a-tu-la Kālakañcikā, là cõi a-tu-la thấp nhất. ",
  "dn24:1.7.20": "Chết rồi, xác ông ta sẽ bị vứt bỏ ở nghĩa địa cỏ tranh. ",
  "dn24:1.7.21": "Nếu muốn, này Sunakkhatta, ngươi có thể đến gặp du sĩ lõa thể Korakkhattiya và hỏi—",
  "dn24:1.7.22": "Thưa tôn giả Korakkhattiya, tôn giả có biết nơi tái sinh của mình không? ",
  "dn24:1.7.23": "Này Sunakkhatta, có khả năng du sĩ lõa thể Korakkhattiya sẽ trả lời ngươi—",
  "dn24:1.7.24": "Thưa tôn giả Sunakkhatta, tôi biết nơi tái sinh của tôi; ",
  "dn24:1.7.25": "cõi a-tu-la Kālakañcikā là cõi a-tu-la thấp nhất, tôi đã tái sinh ở đó.’ ",
  "dn24:1.8.1": "Rồi, này Bhaggava, Sunakkhatta, con trai dòng Licchavi, đến chỗ du sĩ lõa thể Korakkhattiya; đến nơi, anh ta nói với du sĩ lõa thể Korakkhattiya: ",
  "dn24:1.8.2": "‘Thưa tôn giả Korakkhattiya, Sa-môn Gotama đã tuyên bố về ông rằng—",
  "dn24:1.8.3": "Du sĩ lõa thể Korakkhattiya sẽ chết vì bội thực sau bảy ngày. ",
  "dn24:1.8.4": "Chết rồi, ông ta sẽ tái sinh vào cõi a-tu-la Kālakañcikā, là cõi a-tu-la thấp nhất. ",
  "dn24:1.8.5": "Chết rồi, xác ông ta sẽ bị vứt bỏ ở nghĩa địa cỏ tranh. ",
  "dn24:1.8.6": "Thưa tôn giả Korakkhattiya, xin ông hãy ăn có điều độ, uống có điều độ. ",
  "dn24:1.8.7": "Để cho lời Sa-môn Gotama trở thành sai lầm.’ ",
  "dn24:1.8.8": "Rồi, này Bhaggava, Sunakkhatta, con trai dòng Licchavi, đếm từng ngày, đêm cho đến bảy ngày đêm, vì không tin Đức Như Lai. ",
  "dn24:1.8.9": "Rồi, này Bhaggava, đúng ngày thứ bảy, du sĩ lõa thể Korakkhattiya chết vì bội thực. ",
  "dn24:1.8.10": "Chết rồi, ông ta tái sinh vào cõi a-tu-la Kālakañcikā, là cõi a-tu-la thấp nhất. ",
  "dn24:1.8.11": "Chết rồi, xác ông ta bị vứt bỏ ở nghĩa địa cỏ tranh. ",
  "dn24:1.9.1": "Này Bhaggava, Sunakkhatta, con trai dòng Licchavi, nghe: ",
  "dn24:1.9.2": "‘Nghe nói du sĩ lõa thể Korakkhattiya đã chết vì bội thực và xác bị vứt bỏ ở nghĩa địa cỏ tranh.’ ",
  "dn24:1.9.3": "Rồi, này Bhaggava, Sunakkhatta, con trai dòng Licchavi, đến nghĩa địa cỏ tranh, đến chỗ du sĩ lõa thể Korakkhattiya; đến nơi, vỗ ba lần bằng tay vào du sĩ lõa thể Korakkhattiya: ",
  "dn24:1.9.4": "‘Thưa tôn giả Korakkhattiya, ông có biết nơi tái sinh của mình không?’ ",
  "dn24:1.9.5": "Rồi, này Bhaggava, du sĩ lõa thể Korakkhattiya lấy tay xoa lưng mà ngồi dậy. ",
  "dn24:1.9.6": "‘Thưa tôn giả Sunakkhatta, tôi biết nơi tái sinh của tôi. ",
  "dn24:1.9.7": "Cõi a-tu-la Kālakañcikā là cõi a-tu-la thấp nhất, tôi đã tái sinh ở đó’, nói xong lại nằm ngửa ra đó. ",
  "dn24:1.10.1": "Rồi, này Bhaggava, Sunakkhatta, con trai dòng Licchavi, đến chỗ Ta; đến nơi, đảnh lễ Ta rồi ngồi xuống một bên. Này Bhaggava, Ta nói với Sunakkhatta, con trai dòng Licchavi, đang ngồi một bên: ",
  "dn24:1.10.2": "‘Ngươi nghĩ sao, này Sunakkhatta, ",
  "dn24:1.10.3": "điều Ta đã tuyên bố về du sĩ lõa thể Korakkhattiya có xảy ra đúng như vậy không, hay khác đi?’ ",
  "dn24:1.10.4": "‘Bạch Thế Tôn, điều Đức Thế Tôn đã tuyên bố về du sĩ lõa thể Korakkhattiya đã xảy ra đúng như vậy, không khác.’ ",
  "dn24:1.10.5": "‘Ngươi nghĩ sao, này Sunakkhatta, ",
  "dn24:1.10.6": "nếu vậy, thần thông vượt quá pháp người thường có được biểu diễn hay không được biểu diễn?’ ",
  "dn24:1.10.7": "‘Bạch Thế Tôn, nếu vậy thần thông vượt quá pháp người thường đã được biểu diễn, chứ không phải không.’ ",
  "dn24:1.10.8": "‘Này kẻ ngu si, dù Ta đã biểu diễn thần thông vượt quá pháp người thường như vậy, ngươi lại nói với Ta—",
  "dn24:1.10.9": "Bạch Thế Tôn, nhưng Đức Thế Tôn không biểu diễn thần thông vượt quá pháp người thường cho con. ",
  "dn24:1.10.10": "Hãy xem, này kẻ ngu si, lỗi của ngươi lớn biết bao.’ ",
  "dn24:1.10.11": "Như vậy, này Bhaggava, dù được Ta nói, Sunakkhatta, con trai dòng Licchavi, vẫn từ bỏ Pháp và Luật này, như kẻ đã định đọa vào địa ngục. ",
  "dn24:1.11.0": "3. Chuyện Du Sĩ Lõa Thể Kaḷāramaṭṭaka ",
  "dn24:1.11.1": "Này Bhaggava, có một lần Ta đang ở Vesāli, trong Đại Lâm, tại giảng đường Kūṭāgāra. ",
  "dn24:1.11.2": "Lúc bấy giờ, có một du sĩ lõa thể tên Kaḷāramaṭṭaka trú ở Vesāli, đã đạt đến đỉnh cao của lợi dưỡng và danh vọng ở làng Vajji. ",
  "dn24:1.11.3": "Ông ta đã thọ trì bảy hạnh: ",
  "dn24:1.11.4": "‘Suốt đời tôi sẽ sống lõa thể, không mặc y phục; suốt đời tôi sẽ sống phạm hạnh, không hành dâm; suốt đời tôi sẽ sống nhờ rượu và thịt, không ăn cơm và cháo bột. ",
  "dn24:1.11.5": "Phía Đông Vesāli có đền Udena, tôi sẽ không vượt qua đó; phía Nam Vesāli có đền Gotamaka, tôi sẽ không vượt qua đó; phía Tây Vesāli có đền Sattamba, tôi sẽ không vượt qua đó; phía Bắc Vesāli có đền Bahuputta, tôi sẽ không vượt qua đó.’ ",
  "dn24:1.11.6": "Do thọ trì bảy hạnh này, ông ta đã đạt đến đỉnh cao của lợi dưỡng và danh vọng ở làng Vajji. ",
  "dn24:1.12.1": "Rồi, này Bhaggava, Sunakkhatta, con trai dòng Licchavi, đến chỗ du sĩ lõa thể Kaḷāramaṭṭaka; đến nơi, đặt câu hỏi với du sĩ lõa thể Kaḷāramaṭṭaka. ",
  "dn24:1.12.2": "Du sĩ lõa thể Kaḷāramaṭṭaka được hỏi mà không trả lời được. ",
  "dn24:1.12.3": "Không trả lời được, ông ta tỏ ra giận dữ, sân hận và bất mãn. ",
  "dn24:1.12.4": "Rồi, này Bhaggava, Sunakkhatta, con trai dòng Licchavi, nghĩ: ",
  "dn24:1.12.5": "‘Than ôi, chúng ta đã xúc phạm vị Sa-môn A-la-hán tốt đẹp. ",
  "dn24:1.12.6": "Đừng để điều này gây ra đau khổ và bất lợi cho chúng ta lâu dài.’ ",
  "dn24:1.13.1": "Rồi, này Bhaggava, Sunakkhatta, con trai dòng Licchavi, đến chỗ Ta; đến nơi, đảnh lễ Ta rồi ngồi xuống một bên. Này Bhaggava, Ta nói với Sunakkhatta, con trai dòng Licchavi, đang ngồi một bên: ",
  "dn24:1.13.2": "‘Này kẻ ngu si, ngươi vẫn còn tự xưng là Sa-môn, đệ tử dòng Thích-ca sao?’ ",
  "dn24:1.13.3": "‘Bạch Thế Tôn, tại sao Đức Thế Tôn lại nói với con như vầy—",
  "dn24:1.13.4": "Này kẻ ngu si, ngươi vẫn còn tự xưng là Sa-môn, đệ tử dòng Thích-ca sao?’ ",
  "dn24:1.13.5": "‘Này Sunakkhatta, ngươi đã đến chỗ du sĩ lõa thể Kaḷāramaṭṭaka và đặt câu hỏi chẳng phải sao? ",
  "dn24:1.13.6": "Du sĩ lõa thể Kaḷāramaṭṭaka được hỏi mà không trả lời được. ",
  "dn24:1.13.7": "Không trả lời được, ông ta tỏ ra giận dữ, sân hận và bất mãn. ",
  "dn24:1.13.8": "Ngươi đã nghĩ: ",
  "dn24:1.13.9": "“Than ôi, chúng ta đã xúc phạm vị Sa-môn A-la-hán tốt đẹp. ",
  "dn24:1.13.10": "Đừng để điều này gây ra đau khổ và bất lợi cho chúng ta lâu dài.”’ ",
  "dn24:1.13.11": "‘Thưa vâng, bạch Thế Tôn. ",
  "dn24:1.13.12": "Nhưng bạch Thế Tôn, tại sao Đức Thế Tôn lại keo kiệt với quả A-la-hán?’ ",
  "dn24:1.13.13": "‘Này kẻ ngu si, Ta không keo kiệt với quả A-la-hán, ",
  "dn24:1.13.14": "tà kiến xấu này chỉ khởi lên nơi ngươi, hãy từ bỏ nó. ",
  "dn24:1.13.15": "Đừng để nó gây ra đau khổ và bất lợi cho ngươi lâu dài. ",
  "dn24:1.13.16": "Này Sunakkhatta, ngươi nghĩ rằng du sĩ lõa thể Kaḷāramaṭṭaka—",
  "dn24:1.13.17": "Sa-môn này là người tốt; không lâu nữa ông ta sẽ mặc y phục, sống với vợ con, ăn cơm và cháo bột, vượt qua tất cả các đền ở Vesāli, và chết trong cảnh mất hết danh vọng.’ ",
  "dn24:1.13.18": "Rồi, này Bhaggava, không lâu sau, du sĩ lõa thể Kaḷāramaṭṭaka đã mặc y phục, sống với vợ con, ăn cơm và cháo bột, vượt qua tất cả các đền ở Vesāli, và chết trong cảnh mất hết danh vọng. ",
  "dn24:1.14.1": "Này Bhaggava, Sunakkhatta, con trai dòng Licchavi, nghe: ",
  "dn24:1.14.2": "‘Nghe nói du sĩ lõa thể Kaḷāramaṭṭaka đã mặc y phục, sống với vợ con, ăn cơm và cháo bột, vượt qua tất cả các đền ở Vesāli, và đã chết trong cảnh mất hết danh vọng.’ ",
  "dn24:1.14.3": "Rồi, này Bhaggava, Sunakkhatta, con trai dòng Licchavi, đến chỗ Ta; đến nơi, đảnh lễ Ta rồi ngồi xuống một bên. Này Bhaggava, Ta nói với Sunakkhatta, con trai dòng Licchavi, đang ngồi một bên: ",
  "dn24:1.14.4": "‘Ngươi nghĩ sao, này Sunakkhatta, ",
  "dn24:1.14.5": "điều Ta đã tuyên bố về du sĩ lõa thể Kaḷāramaṭṭaka có xảy ra đúng như vậy không, hay khác đi?’ ",
  "dn24:1.14.6": "‘Bạch Thế Tôn, điều Đức Thế Tôn đã tuyên bố về du sĩ lõa thể Kaḷāramaṭṭaka đã xảy ra đúng như vậy, không khác.’ ",
  "dn24:1.14.7": "‘Ngươi nghĩ sao, này Sunakkhatta, ",
  "dn24:1.14.8": "nếu vậy, thần thông vượt quá pháp người thường có được biểu diễn hay không được biểu diễn?’ ",
  "dn24:1.14.9": "‘Bạch Thế Tôn, nếu vậy thần thông vượt quá pháp người thường đã được biểu diễn, chứ không phải không.’ ",
  "dn24:1.14.10": "‘Này kẻ ngu si, dù Ta đã biểu diễn thần thông vượt quá pháp người thường như vậy, ngươi lại nói với Ta: ",
  "dn24:1.14.11": "“Bạch Thế Tôn, nhưng Đức Thế Tôn không biểu diễn thần thông vượt quá pháp người thường cho con.” ",
  "dn24:1.14.12": "Hãy xem, này kẻ ngu si, lỗi của ngươi lớn biết bao.’ ",
  "dn24:1.14.13": "Như vậy, này Bhaggava, dù được Ta nói, Sunakkhatta, con trai dòng Licchavi, vẫn từ bỏ Pháp và Luật này, như kẻ đã định đọa vào địa ngục. ",
  "dn24:1.15.0": "4. Chuyện Du Sĩ Lõa Thể Pāthikaputta ",
  "dn24:1.15.1": "Này Bhaggava, có một lần Ta đang ở ngay tại Vesāli, trong Đại Lâm, tại giảng đường Kūṭāgāra. ",
  "dn24:1.15.2": "Lúc bấy giờ, có một du sĩ lõa thể tên Pāthikaputta trú ở Vesāli, đã đạt đến đỉnh cao của lợi dưỡng và danh vọng ở làng Vajji. ",
  "dn24:1.15.3": "Ông ta nói trước hội chúng ở Vesāli như vầy: ",
  "dn24:1.15.4": "‘Sa-môn Gotama tự xưng là người có trí tuệ, tôi cũng là người có trí tuệ. ",
  "dn24:1.15.5": "Người có trí tuệ cần phải biểu diễn thần thông vượt quá pháp người thường với người có trí tuệ khác. ",
  "dn24:1.15.6": "Sa-môn Gotama hãy đi nửa đường, tôi cũng sẽ đi nửa đường. ",
  "dn24:1.15.7": "Ở đó, cả hai chúng tôi sẽ biểu diễn thần thông vượt quá pháp người thường. ",
  "dn24:1.15.8": "Nếu Sa-môn Gotama biểu diễn một lần thần thông vượt quá pháp người thường, tôi sẽ biểu diễn hai lần. ",
  "dn24:1.15.9": "Nếu Sa-môn Gotama biểu diễn hai lần thần thông vượt quá pháp người thường, tôi sẽ biểu diễn bốn lần. ",
  "dn24:1.15.10": "Nếu Sa-môn Gotama biểu diễn bốn lần thần thông vượt quá pháp người thường, tôi sẽ biểu diễn tám lần. ",
  "dn24:1.15.11": "Như vậy, Sa-môn Gotama biểu diễn bao nhiêu lần thần thông vượt quá pháp người thường, tôi sẽ biểu diễn gấp đôi.’ ",
  "dn24:1.16.1": "Rồi, này Bhaggava, Sunakkhatta, con trai dòng Licchavi, đến chỗ Ta; đến nơi, đảnh lễ Ta rồi ngồi xuống một bên. Ngồi một bên rồi, này Bhaggava, Sunakkhatta, con trai dòng Licchavi, nói với Ta: ",
  "dn24:1.16.2": "‘Bạch Thế Tôn, du sĩ lõa thể Pāthikaputta đang trú ở Vesāli, đã đạt đến đỉnh cao của lợi dưỡng và danh vọng ở làng Vajji. ",
  "dn24:1.16.3": "Ông ta nói trước hội chúng ở Vesāli như vầy: ",
  "dn24:1.16.4": "“Sa-môn Gotama tự xưng là người có trí tuệ, tôi cũng là người có trí tuệ. ",
  "dn24:1.16.5": "Người có trí tuệ cần phải biểu diễn thần thông vượt quá pháp người thường với người có trí tuệ khác. ",
  "dn24:1.16.6": "Sa-môn Gotama hãy đi nửa đường, tôi cũng sẽ đi nửa đường. ",
  "dn24:1.16.7": "Ở đó, cả hai chúng tôi sẽ biểu diễn thần thông vượt quá pháp người thường. ",
  "dn24:1.16.8": "Nếu Sa-môn Gotama biểu diễn một lần thần thông vượt quá pháp người thường, tôi sẽ biểu diễn hai lần. ",
  "dn24:1.16.9": "Nếu Sa-môn Gotama biểu diễn hai lần thần thông vượt quá pháp người thường, tôi sẽ biểu diễn bốn lần. ",
  "dn24:1.16.10": "Nếu Sa-môn Gotama biểu diễn bốn lần thần thông vượt quá pháp người thường, tôi sẽ biểu diễn tám lần. ",
  "dn24:1.16.11": "Như vậy, Sa-môn Gotama biểu diễn bao nhiêu lần thần thông vượt quá pháp người thường, tôi sẽ biểu diễn gấp đôi.”’ ",
  "dn24:1.16.12": "Khi nghe vậy, này Bhaggava, Ta nói với Sunakkhatta, con trai dòng Licchavi: ",
  "dn24:1.16.13": "‘Này Sunakkhatta, du sĩ lõa thể Pāthikaputta không thể đến gặp mặt Ta mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy. ",
  "dn24:1.16.14": "Dù ông ta có nghĩ rằng—",
  "dn24:1.16.15": "Ta sẽ đến gặp mặt Sa-môn Gotama mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy, thì đầu ông ta cũng sẽ vỡ ra.’ ",
  "dn24:1.17.1": "‘Bạch Thế Tôn, xin Đức Thế Tôn giữ gìn lời nói ấy, xin Đức Thiện Thệ giữ gìn lời nói ấy.’ ",
  "dn24:1.17.2": "‘Này Sunakkhatta, tại sao ngươi lại nói với Ta—",
  "dn24:1.17.3": "Bạch Thế Tôn, xin Đức Thế Tôn giữ gìn lời nói ấy, xin Đức Thiện Thệ giữ gìn lời nói ấy?’ ",
  "dn24:1.17.4": "‘Bạch Thế Tôn, Đức Thế Tôn đã tuyên bố lời nói này một cách chắc chắn—",
  "dn24:1.17.5": "du sĩ lõa thể Pāthikaputta không thể đến gặp mặt Ta mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy. ",
  "dn24:1.17.6": "Dù ông ta có nghĩ rằng—",
  "dn24:1.17.7": "Ta sẽ đến gặp mặt Sa-môn Gotama mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy, thì đầu ông ta cũng sẽ vỡ ra. ",
  "dn24:1.17.8": "Nhưng bạch Thế Tôn, giả như du sĩ lõa thể Pāthikaputta đến gặp mặt Đức Thế Tôn bằng hình dạng biến đổi, thì lời của Đức Thế Tôn sẽ trở thành sai.’ ",
  "dn24:1.18.1": "‘Này Sunakkhatta, liệu Đức Như Lai có nói lời nào đi theo hai chiều không?’ ",
  "dn24:1.18.2": "‘Nhưng bạch Thế Tôn, có phải Đức Thế Tôn đã dùng tâm đọc được tâm của du sĩ lõa thể Pāthikaputta rằng—",
  "dn24:1.18.3": "du sĩ lõa thể Pāthikaputta không thể đến gặp mặt Ta mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy. ",
  "dn24:1.18.4": "Dù ông ta có nghĩ rằng—",
  "dn24:1.18.5": "Ta sẽ đến gặp mặt Sa-môn Gotama mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy, thì đầu ông ta cũng sẽ vỡ ra? ",
  "dn24:1.18.6": "Hay là chư thiên đã báo cho Đức Thế Tôn biết điều này—",
  "dn24:1.18.7": "Bạch Thế Tôn, du sĩ lõa thể Pāthikaputta không thể đến gặp mặt Đức Thế Tôn mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy. ",
  "dn24:1.18.8": "Dù ông ta có nghĩ rằng—",
  "dn24:1.18.9": "Ta sẽ đến gặp mặt Sa-môn Gotama mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy, thì đầu ông ta cũng sẽ vỡ ra?’ ",
  "dn24:1.18.10": "‘Này Sunakkhatta, Ta đã dùng tâm đọc được tâm của du sĩ lõa thể Pāthikaputta rằng—",
  "dn24:1.18.11": "du sĩ lõa thể Pāthikaputta không thể đến gặp mặt Ta mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy. ",
  "dn24:1.18.12": "Dù ông ta có nghĩ rằng—",
  "dn24:1.18.13": "Ta sẽ đến gặp mặt Sa-môn Gotama mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy, thì đầu ông ta cũng sẽ vỡ ra. ",
  "dn24:1.18.14": "Chư thiên cũng đã báo cho Ta biết điều này—",
  "dn24:1.18.15": "Bạch Thế Tôn, du sĩ lõa thể Pāthikaputta không thể đến gặp mặt Đức Thế Tôn mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy. ",
  "dn24:1.18.16": "Dù ông ta có nghĩ rằng—",
  "dn24:1.18.17": "Ta sẽ đến gặp mặt Sa-môn Gotama mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy, thì đầu ông ta cũng sẽ vỡ ra. ",
  "dn24:1.18.18": "Ajita, vị đại tướng của người Licchavi, vừa mới chết và tái sinh vào cõi trời Ba Mươi Ba. ",
  "dn24:1.18.19": "Vị ấy cũng đã đến gặp Ta và báo như vầy—",
  "dn24:1.18.20": "Bạch Thế Tôn, du sĩ lõa thể Pāthikaputta là kẻ không biết xấu hổ; ",
  "dn24:1.18.21": "bạch Thế Tôn, du sĩ lõa thể Pāthikaputta là kẻ nói dối. ",
  "dn24:1.18.22": "Bạch Thế Tôn, du sĩ lõa thể Pāthikaputta còn tuyên bố về con ở làng Vajji—",
  "dn24:1.18.23": "Ajita, vị đại tướng của người Licchavi, đã tái sinh vào đại địa ngục. ",
  "dn24:1.18.24": "Nhưng bạch Thế Tôn, con không tái sinh vào đại địa ngục; ",
  "dn24:1.18.25": "con đã tái sinh vào cõi trời Ba Mươi Ba. ",
  "dn24:1.18.26": "Bạch Thế Tôn, du sĩ lõa thể Pāthikaputta là kẻ không biết xấu hổ; ",
  "dn24:1.18.27": "bạch Thế Tôn, du sĩ lõa thể Pāthikaputta là kẻ nói dối; ",
  "dn24:1.18.28": "và bạch Thế Tôn, du sĩ lõa thể Pāthikaputta không thể đến gặp mặt Đức Thế Tôn mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy. ",
  "dn24:1.18.29": "Dù ông ta có nghĩ rằng—",
  "dn24:1.18.30": "Ta sẽ đến gặp mặt Sa-môn Gotama mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy, thì đầu ông ta cũng sẽ vỡ ra. ",
  "dn24:1.18.31": "Như vậy, này Sunakkhatta, Ta đã dùng tâm đọc được tâm của du sĩ lõa thể Pāthikaputta rằng du sĩ lõa thể Pāthikaputta không thể đến gặp mặt Ta mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy. ",
  "dn24:1.18.32": "Dù ông ta có nghĩ rằng—",
  "dn24:1.18.33": "Ta sẽ đến gặp mặt Sa-môn Gotama mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy, thì đầu ông ta cũng sẽ vỡ ra. ",
  "dn24:1.18.34": "Chư thiên cũng đã báo cho Ta biết điều này—",
  "dn24:1.18.35": "Bạch Thế Tôn, du sĩ lõa thể Pāthikaputta không thể đến gặp mặt Đức Thế Tôn mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy. ",
  "dn24:1.18.36": "Dù ông ta có nghĩ rằng—",
  "dn24:1.18.37": "Ta sẽ đến gặp mặt Sa-môn Gotama mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy, thì đầu ông ta cũng sẽ vỡ ra. ",
  "dn24:1.18.38": "Vậy nên, này Sunakkhatta, sau khi đi khất thực ở Vesāli, thọ trai xong và trở về, Ta sẽ đến khu vườn của du sĩ lõa thể Pāthikaputta để nghỉ ngày. ",
  "dn24:1.18.39": "Này Sunakkhatta, nếu ngươi muốn, hãy báo tin cho ai tùy ý ngươi.’ ",
  "dn24:1.19.0": "5. Câu Chuyện Về Thần Thông ",
  "dn24:1.19.1": "Rồi, này Bhaggava, vào buổi sáng, Ta đắp y, mang y bát, vào Vesāli khất thực. ",
  "dn24:1.19.2": "Sau khi khất thực ở Vesāli, thọ trai xong và trở về, Ta đi đến khu vườn của du sĩ lõa thể Pāthikaputta để nghỉ ngày. ",
  "dn24:1.19.3": "Rồi, này Bhaggava, Sunakkhatta, con trai dòng Licchavi, vội vã đi vào Vesāli, đến chỗ các người Licchavi trứ danh; đến nơi, anh ta nói với các người Licchavi trứ danh: ",
  "dn24:1.19.4": "‘Thưa các vị, Đức Thế Tôn sau khi khất thực ở Vesāli, thọ trai xong và trở về, đã đi đến khu vườn của du sĩ lõa thể Pāthikaputta để nghỉ ngày. ",
  "dn24:1.19.5": "Các vị hãy đi, các vị hãy đi, sẽ có thần thông vượt quá pháp người thường của các Sa-môn tốt đẹp.’ ",
  "dn24:1.19.6": "Rồi, này Bhaggava, các người Licchavi trứ danh nghĩ: ",
  "dn24:1.19.7": "‘Nghe nói sẽ có thần thông vượt quá pháp người thường của các Sa-môn tốt đẹp; ",
  "dn24:1.19.8": "vậy chúng ta hãy đi xem.’ ",
  "dn24:1.19.9": "Anh ta lại đến chỗ các Bà-la-môn trứ danh giàu có, các gia chủ giàu có, các Sa-môn Bà-la-môn thuộc các ngoại đạo khác nhau. Đến nơi, anh ta nói với các Sa-môn Bà-la-môn thuộc các ngoại đạo khác nhau trứ danh: ",
  "dn24:1.19.10": "‘Thưa các vị, Đức Thế Tôn sau khi khất thực ở Vesāli, thọ trai xong và trở về, đã đi đến khu vườn của du sĩ lõa thể Pāthikaputta để nghỉ ngày. ",
  "dn24:1.19.11": "Các vị hãy đi, các vị hãy đi, sẽ có thần thông vượt quá pháp người thường của các Sa-môn tốt đẹp.’ ",
  "dn24:1.19.12": "Rồi, này Bhaggava, các Sa-môn Bà-la-môn thuộc các ngoại đạo khác nhau trứ danh nghĩ: ",
  "dn24:1.19.13": "‘Nghe nói sẽ có thần thông vượt quá pháp người thường của các Sa-môn tốt đẹp; ",
  "dn24:1.19.14": "vậy chúng ta hãy đi xem.’ ",
  "dn24:1.19.15": "Rồi, này Bhaggava, các người Licchavi trứ danh, các Bà-la-môn trứ danh giàu có, các gia chủ giàu có, các Sa-môn Bà-la-môn thuộc các ngoại đạo khác nhau đi đến khu vườn của du sĩ lõa thể Pāthikaputta. ",
  "dn24:1.19.16": "Hội chúng ấy thật lớn, này Bhaggava, gồm nhiều trăm, nhiều ngàn người. ",
  "dn24:1.20.1": "Này Bhaggava, du sĩ lõa thể Pāthikaputta nghe: ",
  "dn24:1.20.2": "‘Nghe nói các người Licchavi trứ danh đã đi đến, các Bà-la-môn trứ danh giàu có, các gia chủ giàu có, các Sa-môn Bà-la-môn thuộc các ngoại đạo khác nhau trứ danh đã đi đến. ",
  "dn24:1.20.3": "Và Sa-môn Gotama cũng đang ngồi nghỉ ngày tại khu vườn của ta.’ ",
  "dn24:1.20.4": "Nghe vậy, nơi ông ta sinh ra sợ hãi, kinh hãi, rởn tóc gáy. ",
  "dn24:1.20.5": "Rồi, này Bhaggava, du sĩ lõa thể Pāthikaputta sợ hãi, kinh hãi, rởn tóc gáy, đi đến tu viện du sĩ Tinduka-khāṇu. ",
  "dn24:1.20.6": "Hội chúng ấy nghe, này Bhaggava: ",
  "dn24:1.20.7": "‘Nghe nói du sĩ lõa thể Pāthikaputta sợ hãi, kinh hãi, rởn tóc gáy, đã đi đến tu viện du sĩ Tinduka-khāṇu.’ ",
  "dn24:1.20.8": "Rồi, này Bhaggava, hội chúng ấy bảo một người: ",
  "dn24:1.20.9": "‘Này người bạn, hãy đi đến tu viện du sĩ Tinduka-khāṇu, đến chỗ du sĩ lõa thể Pāthikaputta. Đến nơi, hãy nói với du sĩ lõa thể Pāthikaputta như vầy: ",
  "dn24:1.20.10": "“Thưa tôn giả Pāthikaputta, hãy đến, các người Licchavi trứ danh đã đến, các Bà-la-môn trứ danh giàu có, các gia chủ giàu có, các Sa-môn Bà-la-môn thuộc các ngoại đạo khác nhau trứ danh đã đến, Sa-môn Gotama đang ngồi nghỉ ngày tại khu vườn của tôn giả; ",
  "dn24:1.20.11": "và thưa tôn giả Pāthikaputta, tôn giả đã nói lời này ở Vesāli trước hội chúng: ",
  "dn24:1.20.12": "Sa-môn Gotama tự xưng là người có trí tuệ, tôi cũng là người có trí tuệ. ",
  "dn24:1.20.13": "Người có trí tuệ cần phải biểu diễn thần thông vượt quá pháp người thường với người có trí tuệ khác. ",
  "dn24:1.20.14": "Sa-môn Gotama hãy đi nửa đường, tôi cũng sẽ đi nửa đường. ",
  "dn24:1.20.15": "Ở đó, cả hai chúng tôi sẽ biểu diễn thần thông vượt quá pháp người thường. ",
  "dn24:1.20.16": "Nếu Sa-môn Gotama biểu diễn một lần thần thông vượt quá pháp người thường, tôi sẽ biểu diễn hai lần. ",
  "dn24:1.20.17": "Nếu Sa-môn Gotama biểu diễn hai lần thần thông vượt quá pháp người thường, tôi sẽ biểu diễn bốn lần. ",
  "dn24:1.20.18": "Nếu Sa-môn Gotama biểu diễn bốn lần thần thông vượt quá pháp người thường, tôi sẽ biểu diễn tám lần. ",
  "dn24:1.20.19": "Như vậy, Sa-môn Gotama biểu diễn bao nhiêu lần thần thông vượt quá pháp người thường, tôi sẽ biểu diễn gấp đôi.” ",
  "dn24:1.20.20": "Vậy thưa tôn giả Pāthikaputta, hãy đến nửa đường. ",
  "dn24:1.20.21": "Sa-môn Gotama đã đến trước nhất và đang ngồi nghỉ ngày tại khu vườn của tôn giả.’ ",
  "dn24:1.21.1": "‘Thưa vâng,’ này Bhaggava, người ấy đáp lời hội chúng rồi đi đến tu viện du sĩ Tinduka-khāṇu, đến chỗ du sĩ lõa thể Pāthikaputta. Đến nơi, người ấy nói với du sĩ lõa thể Pāthikaputta: ",
  "dn24:1.21.2": "‘Thưa tôn giả Pāthikaputta, hãy đến, các người Licchavi trứ danh đã đến, các Bà-la-môn trứ danh giàu có, các gia chủ giàu có, các Sa-môn Bà-la-môn thuộc các ngoại đạo khác nhau trứ danh đã đến. ",
  "dn24:1.21.3": "Sa-môn Gotama đang ngồi nghỉ ngày tại khu vườn của tôn giả. ",
  "dn24:1.21.4": "Và thưa tôn giả Pāthikaputta, tôn giả đã nói lời này ở Vesāli trước hội chúng—",
  "dn24:1.21.5": "Sa-môn Gotama tự xưng là người có trí tuệ; tôi cũng là người có trí tuệ. ",
  "dn24:1.21.6": "Người có trí tuệ cần phải biểu diễn thần thông vượt quá pháp người thường với người có trí tuệ khác …nt… ",
  "dn24:1.21.7": "tôi sẽ biểu diễn gấp đôi. ",
  "dn24:1.21.8": "Vậy thưa tôn giả Pāthikaputta, hãy đến nửa đường. ",
  "dn24:1.21.9": "Sa-môn Gotama đã đến trước nhất và đang ngồi nghỉ ngày tại khu vườn của tôn giả.’ ",
  "dn24:1.21.10": "Khi nghe vậy, này Bhaggava, du sĩ lõa thể Pāthikaputta nói: ‘Tôi đến, bạn, tôi đến, bạn’ rồi vặn vẹo ngay tại chỗ, không thể đứng dậy khỏi ghế. ",
  "dn24:1.21.11": "Rồi, này Bhaggava, người ấy nói với du sĩ lõa thể Pāthikaputta: ",
  "dn24:1.21.12": "‘Thưa tôn giả Pāthikaputta, cái gì với ông vậy? Mông của ông dính vào ghế, hay ghế dính vào mông của ông? ",
  "dn24:1.21.13": "Ông nói “Tôi đến, bạn, tôi đến, bạn” rồi vặn vẹo ngay tại chỗ, không thể đứng dậy khỏi ghế.’ ",
  "dn24:1.21.14": "Dù được nói như vậy, này Bhaggava, du sĩ lõa thể Pāthikaputta vẫn nói: ‘Tôi đến, bạn, tôi đến, bạn’ rồi vặn vẹo ngay tại chỗ, không thể đứng dậy khỏi ghế. ",
  "dn24:1.22.1": "Khi người ấy biết, này Bhaggava: ",
  "dn24:1.22.2": "‘Du sĩ lõa thể Pāthikaputta này đã thất bại rồi. ",
  "dn24:1.22.3": "Ông ta nói “Tôi đến, bạn, tôi đến, bạn” rồi vặn vẹo ngay tại chỗ, không thể đứng dậy khỏi ghế.’ ",
  "dn24:1.22.4": "Anh ta trở về hội chúng và báo như vầy: ",
  "dn24:1.22.5": "‘Thưa các vị, du sĩ lõa thể Pāthikaputta đã thất bại rồi. ",
  "dn24:1.22.6": "Ông ta nói “Tôi đến, bạn, tôi đến, bạn” rồi vặn vẹo ngay tại chỗ, không thể đứng dậy khỏi ghế.’ ",
  "dn24:1.22.7": "Khi nghe vậy, này Bhaggava, Ta nói với hội chúng ấy: ",
  "dn24:1.22.8": "‘Thưa các vị, du sĩ lõa thể Pāthikaputta không thể đến gặp mặt Ta mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy. ",
  "dn24:1.22.9": "Dù ông ta có nghĩ rằng—",
  "dn24:1.22.10": "Ta sẽ đến gặp mặt Sa-môn Gotama mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy, thì đầu ông ta cũng sẽ vỡ ra.’ ",
  "dn24:1.22.11": "Phần tụng đọc thứ nhất đã kết thúc. ",
  "dn24:2.1.1": "Rồi, này Bhaggava, có một vị đại thần Licchavi đứng dậy khỏi chỗ ngồi và nói với hội chúng: ",
  "dn24:2.1.2": "‘Vậy thì, thưa các vị, xin hãy chờ một chút, để tôi đi. ",
  "dn24:2.1.3": "Có lẽ tôi có thể đưa du sĩ lõa thể Pāthikaputta đến hội chúng này.’ ",
  "dn24:2.1.4": "Rồi, này Bhaggava, vị đại thần Licchavi ấy đi đến tu viện du sĩ Tinduka-khāṇu, đến chỗ du sĩ lõa thể Pāthikaputta. Đến nơi, ông ấy nói với du sĩ lõa thể Pāthikaputta: ",
  "dn24:2.1.5": "‘Thưa tôn giả Pāthikaputta, hãy đến, tốt hơn cho ông là hãy đến, các người Licchavi trứ danh đã đến, các Bà-la-môn trứ danh giàu có, các gia chủ giàu có, các Sa-môn Bà-la-môn thuộc các ngoại đạo khác nhau trứ danh đã đến. Sa-môn Gotama đang ngồi nghỉ ngày tại khu vườn của tôn giả. ",
  "dn24:2.1.6": "Và thưa tôn giả Pāthikaputta, tôn giả đã nói lời này ở Vesāli trước hội chúng—",
  "dn24:2.1.7": "Sa-môn Gotama tự xưng là người có trí tuệ …nt… ",
  "dn24:2.1.8": "tôi sẽ biểu diễn gấp đôi. ",
  "dn24:2.1.9": "Vậy thưa tôn giả Pāthikaputta, hãy đến nửa đường. ",
  "dn24:2.1.10": "Sa-môn Gotama đã đến trước nhất và đang ngồi nghỉ ngày tại khu vườn của tôn giả. ",
  "dn24:2.1.11": "Và thưa tôn giả Pāthikaputta, Sa-môn Gotama đã nói lời này trước hội chúng—",
  "dn24:2.1.12": "du sĩ lõa thể Pāthikaputta không thể đến gặp mặt Ta mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy. ",
  "dn24:2.1.13": "Dù ông ta có nghĩ rằng—",
  "dn24:2.1.14": "Ta sẽ đến gặp mặt Sa-môn Gotama mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy, thì đầu ông ta cũng sẽ vỡ ra. ",
  "dn24:2.1.15": "Thưa tôn giả Pāthikaputta, hãy đến, chỉ bằng việc ông đến chúng ta sẽ chiến thắng, Sa-môn Gotama sẽ thất bại.’ ",
  "dn24:2.2.1": "Khi nghe vậy, này Bhaggava, du sĩ lõa thể Pāthikaputta nói: ‘Tôi đến, bạn, tôi đến, bạn’ rồi vặn vẹo ngay tại chỗ, không thể đứng dậy khỏi ghế. ",
  "dn24:2.2.2": "Rồi, này Bhaggava, vị đại thần Licchavi ấy nói với du sĩ lõa thể Pāthikaputta: ",
  "dn24:2.2.3": "‘Thưa tôn giả Pāthikaputta, cái gì với ông vậy? Mông của ông dính vào ghế, hay ghế dính vào mông của ông? ",
  "dn24:2.2.4": "Ông nói “Tôi đến, bạn, tôi đến, bạn” rồi vặn vẹo ngay tại chỗ, không thể đứng dậy khỏi ghế.’ ",
  "dn24:2.2.5": "Dù được nói như vậy, này Bhaggava, du sĩ lõa thể Pāthikaputta vẫn nói: ‘Tôi đến, bạn, tôi đến, bạn’ rồi vặn vẹo ngay tại chỗ, không thể đứng dậy khỏi ghế. ",
  "dn24:2.3.1": "Khi vị đại thần Licchavi ấy biết, này Bhaggava: ",
  "dn24:2.3.2": "‘Du sĩ lõa thể Pāthikaputta này đã thất bại rồi. Ông ta nói “Tôi đến, bạn, tôi đến, bạn” rồi vặn vẹo ngay tại chỗ, không thể đứng dậy khỏi ghế.’ ",
  "dn24:2.3.3": "Ông ấy trở về hội chúng và báo như vầy: ",
  "dn24:2.3.4": "‘Thưa các vị, du sĩ lõa thể Pāthikaputta đã thất bại rồi. Ông ta nói “Tôi đến, bạn, tôi đến, bạn” rồi vặn vẹo ngay tại chỗ, không thể đứng dậy khỏi ghế.’ ",
  "dn24:2.3.5": "Khi nghe vậy, này Bhaggava, Ta nói với hội chúng ấy: ",
  "dn24:2.3.6": "‘Thưa các vị, du sĩ lõa thể Pāthikaputta không thể đến gặp mặt Ta mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy. ",
  "dn24:2.3.7": "Dù ông ta có nghĩ rằng—",
    "dn24:2.3.8": "Ta sẽ đến gặp mặt Sa-môn Gotama mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy, thì đầu ông ta cũng sẽ vỡ ra. ",
  "dn24:2.3.9": "Dù quý vị Licchavi có nghĩ rằng—",
  "dn24:2.3.10": "chúng ta sẽ trói du sĩ lõa thể Pāthikaputta bằng dây da và dùng đôi bò kéo đi, thì dây da sẽ đứt hoặc Pāthikaputta cũng sẽ vỡ ra. ",
  "dn24:2.3.11": "Nhưng du sĩ lõa thể Pāthikaputta không thể đến gặp mặt Ta mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy. ",
  "dn24:2.3.12": "Dù ông ta có nghĩ rằng—",
  "dn24:2.3.13": "Ta sẽ đến gặp mặt Sa-môn Gotama mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy, thì đầu ông ta cũng sẽ vỡ ra.’ ",
  "dn24:2.4.1": "Rồi, này Bhaggava, Jāliya, đệ tử của Dārupattika, đứng dậy khỏi chỗ ngồi và nói với hội chúng: ",
  "dn24:2.4.2": "‘Vậy thì, thưa các vị, xin hãy chờ một chút, để tôi đi; ",
  "dn24:2.4.3": "có lẽ tôi có thể đưa du sĩ lõa thể Pāthikaputta đến hội chúng này.’ ",
  "dn24:2.4.4": "Rồi, này Bhaggava, Jāliya, đệ tử của Dārupattika, đi đến tu viện du sĩ Tinduka-khāṇu, đến chỗ du sĩ lõa thể Pāthikaputta. Đến nơi, anh ấy nói với du sĩ lõa thể Pāthikaputta: ",
  "dn24:2.4.5": "‘Thưa tôn giả Pāthikaputta, hãy đến, tốt hơn cho ông là hãy đến. Các người Licchavi trứ danh đã đến, các Bà-la-môn trứ danh giàu có, các gia chủ giàu có, các Sa-môn Bà-la-môn thuộc các ngoại đạo khác nhau trứ danh đã đến. Sa-môn Gotama đang ngồi nghỉ ngày tại khu vườn của tôn giả. ",
  "dn24:2.4.6": "Và thưa tôn giả Pāthikaputta, tôn giả đã nói lời này ở Vesāli trước hội chúng—",
  "dn24:2.4.7": "Sa-môn Gotama tự xưng là người có trí tuệ …nt… ",
  "dn24:2.4.8": "tôi sẽ biểu diễn gấp đôi. ",
  "dn24:2.4.9": "Vậy thưa tôn giả Pāthikaputta, hãy đến nửa đường. ",
  "dn24:2.4.10": "Sa-môn Gotama đã đến trước nhất và đang ngồi nghỉ ngày tại khu vườn của tôn giả. ",
  "dn24:2.4.11": "Và thưa tôn giả Pāthikaputta, Sa-môn Gotama đã nói lời này trước hội chúng—",
  "dn24:2.4.12": "du sĩ lõa thể Pāthikaputta không thể đến gặp mặt Ta mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy. ",
  "dn24:2.4.13": "Dù ông ta có nghĩ rằng—",
  "dn24:2.4.14": "Ta sẽ đến gặp mặt Sa-môn Gotama mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy, thì đầu ông ta cũng sẽ vỡ ra. ",
  "dn24:2.4.15": "Dù quý vị Licchavi có nghĩ rằng—",
  "dn24:2.4.16": "chúng ta sẽ trói du sĩ lõa thể Pāthikaputta bằng dây da và dùng đôi bò kéo đi, thì dây da sẽ đứt hoặc Pāthikaputta cũng sẽ vỡ ra. ",
  "dn24:2.4.17": "Nhưng du sĩ lõa thể Pāthikaputta không thể đến gặp mặt Ta mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy. ",
  "dn24:2.4.18": "Dù ông ta có nghĩ rằng—",
  "dn24:2.4.19": "Ta sẽ đến gặp mặt Sa-môn Gotama mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy, thì đầu ông ta cũng sẽ vỡ ra. ",
  "dn24:2.4.20": "Thưa tôn giả Pāthikaputta, hãy đến, chỉ bằng việc ông đến chúng ta sẽ chiến thắng, Sa-môn Gotama sẽ thất bại.’ ",
  "dn24:2.5.1": "Khi nghe vậy, này Bhaggava, du sĩ lõa thể Pāthikaputta nói: ‘Tôi đến, bạn, tôi đến, bạn’ rồi vặn vẹo ngay tại chỗ, không thể đứng dậy khỏi ghế. ",
  "dn24:2.5.2": "Rồi, này Bhaggava, Jāliya, đệ tử của Dārupattika, nói với du sĩ lõa thể Pāthikaputta: ",
  "dn24:2.5.3": "‘Thưa tôn giả Pāthikaputta, cái gì với ông vậy? Mông của ông dính vào ghế, hay ghế dính vào mông của ông? ",
  "dn24:2.5.4": "Ông nói “Tôi đến, bạn, tôi đến, bạn” rồi vặn vẹo ngay tại chỗ, không thể đứng dậy khỏi ghế.’ ",
  "dn24:2.5.5": "Dù được nói như vậy, này Bhaggava, du sĩ lõa thể Pāthikaputta vẫn nói: ‘Tôi đến, bạn, tôi đến, bạn’ rồi vặn vẹo ngay tại chỗ, không thể đứng dậy khỏi ghế. ",
  "dn24:2.6.1": "Khi Jāliya, đệ tử của Dārupattika, biết, này Bhaggava: ",
  "dn24:2.6.2": "‘Du sĩ lõa thể Pāthikaputta này đã thất bại rồi. Ông ta nói “Tôi đến, bạn, tôi đến, bạn” rồi vặn vẹo ngay tại chỗ, không thể đứng dậy khỏi ghế.’ Rồi anh ấy nói với ông ta—",
  "dn24:2.6.3": "Ngày xưa, thưa tôn giả Pāthikaputta, có một vị sư tử, vua loài thú, suy nghĩ: ",
  "dn24:2.6.4": "‘Ta hãy dựa vào một khu rừng nào đó làm hang ổ. ",
  "dn24:2.6.5": "Sau khi dựng hang ổ ở đó, buổi chiều ta sẽ ra khỏi hang, ra khỏi hang rồi ta sẽ vươn mình, sau khi vươn mình ta sẽ quan sát bốn phương, sau khi quan sát bốn phương ta sẽ rống tiếng sư tử ba lần, sau khi rống tiếng sư tử ba lần ta sẽ đi tìm mồi. ",
  "dn24:2.6.6": "Ta sẽ giết những con thú tốt nhất trong bầy, ăn thịt mềm nhất rồi trở về chính hang ổ đó.’ ",
  "dn24:2.6.7": "Rồi, thưa tôn giả, vị sư tử, vua loài thú ấy, dựa vào một khu rừng làm hang ổ. ",
  "dn24:2.6.8": "Sau khi dựng hang ổ ở đó, buổi chiều vị ấy ra khỏi hang, ra khỏi hang rồi vị ấy vươn mình, sau khi vươn mình vị ấy quan sát bốn phương, sau khi quan sát bốn phương vị ấy rống tiếng sư tử ba lần, sau khi rống tiếng sư tử ba lần vị ấy đi tìm mồi. ",
  "dn24:2.6.9": "Vị ấy giết những con thú tốt nhất trong bầy, ăn thịt mềm nhất rồi trở về chính hang ổ đó. ",
  "dn24:2.6.10": "Thưa tôn giả Pāthikaputta, có một con chó rừng già lớn lên bằng thức ăn thừa của vị sư tử, vua loài thú ấy, nó kiêu ngạo và mạnh mẽ. ",
  "dn24:2.6.11": "Rồi, thưa tôn giả, con chó rừng già ấy nghĩ: ",
  "dn24:2.6.12": "‘Ta là ai, sư tử vua loài thú là ai. ",
  "dn24:2.6.13": "Ta cũng hãy dựa vào một khu rừng nào đó làm hang ổ. ",
  "dn24:2.6.14": "Sau khi dựng hang ổ ở đó, buổi chiều ta sẽ ra khỏi hang, ra khỏi hang rồi ta sẽ vươn mình, sau khi vươn mình ta sẽ quan sát bốn phương, sau khi quan sát bốn phương ta sẽ rống tiếng sư tử ba lần, sau khi rống tiếng sư tử ba lần ta sẽ đi tìm mồi. ",
  "dn24:2.6.15": "Ta sẽ giết những con thú tốt nhất trong bầy, ăn thịt mềm nhất rồi trở về chính hang ổ đó.’ ",
  "dn24:2.7.1": "Rồi, thưa tôn giả, con chó rừng già ấy dựa vào một khu rừng làm hang ổ. ",
  "dn24:2.7.2": "Sau khi dựng hang ổ ở đó, buổi chiều nó ra khỏi hang, ra khỏi hang rồi nó vươn mình, sau khi vươn mình nó quan sát bốn phương, sau khi quan sát bốn phương định rống tiếng sư tử ba lần, nhưng chỉ tru lên tiếng chó rừng, kêu lên tiếng chó rừng – chó rừng thấp hèn là gì, tiếng sư tử là gì. ",
  "dn24:2.7.3": "Cũng vậy, thưa tôn giả Pāthikaputta, ông sống nhờ uy đức của Đức Thiện Thệ, ăn thức ăn thừa của Đức Thiện Thệ, lại dám nghĩ đến việc xúc phạm Đức Như Lai, bậc A-la-hán, Chánh Đẳng Giác. ",
  "dn24:2.7.4": "Những kẻ như Pāthikaputta thấp hèn là gì, việc xúc phạm các Đức Như Lai, bậc A-la-hán, Chánh Đẳng Giác là gì. ",
  "dn24:2.8.1": "Khi Jāliya, đệ tử của Dārupattika, không thể dùng ví dụ này để khiến du sĩ lõa thể Pāthikaputta rời khỏi chỗ ngồi, này Bhaggava. ",
  "dn24:2.8.2": "Rồi anh ấy nói với ông ta: ",
  "dn24:2.8.3": "‘Tự nhìn mình mà ngỡ là sư tử, ",
  "dn24:2.8.4": "Chó rừng tự cho mình là vua loài thú; ",
  "dn24:2.8.5": "Và nó cứ kêu lên tiếng chó rừng, ",
  "dn24:2.8.6": "Chó rừng thấp hèn là gì, tiếng sư tử là gì. ",
  "dn24:2.8.7": "Cũng vậy, thưa tôn giả Pāthikaputta, ông sống nhờ uy đức của Đức Thiện Thệ, ăn thức ăn thừa của Đức Thiện Thệ, lại dám nghĩ đến việc xúc phạm Đức Như Lai, bậc A-la-hán, Chánh Đẳng Giác. ",
  "dn24:2.8.8": "Những kẻ như Pāthikaputta thấp hèn là gì, việc xúc phạm các Đức Như Lai, bậc A-la-hán, Chánh Đẳng Giác là gì.’ ",
  "dn24:2.9.1": "Khi Jāliya, đệ tử của Dārupattika, không thể dùng ví dụ này để khiến du sĩ lõa thể Pāthikaputta rời khỏi chỗ ngồi, này Bhaggava. ",
  "dn24:2.9.2": "Rồi anh ấy nói với ông ta: ",
  "dn24:2.9.3": "‘Đi theo sau kẻ khác, ",
  "dn24:2.9.4": "Nhìn mình ăn thức ăn thừa; ",
  "dn24:2.9.5": "Chừng nào chưa thấy rõ chính mình, ",
  "dn24:2.9.6": "Chó rừng còn tưởng mình là hổ. ",
  "dn24:2.9.7": "Và nó cứ kêu lên tiếng chó rừng, ",
  "dn24:2.9.8": "Chó rừng thấp hèn là gì, tiếng sư tử là gì. ",
  "dn24:2.9.9": "Cũng vậy, thưa tôn giả Pāthikaputta, ông sống nhờ uy đức của Đức Thiện Thệ, ăn thức ăn thừa của Đức Thiện Thệ, lại dám nghĩ đến việc xúc phạm Đức Như Lai, bậc A-la-hán, Chánh Đẳng Giác. ",
  "dn24:2.9.10": "Những kẻ như Pāthikaputta thấp hèn là gì, việc xúc phạm các Đức Như Lai, bậc A-la-hán, Chánh Đẳng Giác là gì.’ ",
  "dn24:2.10.1": "Khi Jāliya, đệ tử của Dārupattika, không thể dùng ví dụ này để khiến du sĩ lõa thể Pāthikaputta rời khỏi chỗ ngồi, này Bhaggava. ",
  "dn24:2.10.2": "Rồi anh ấy nói với ông ta: ",
  "dn24:2.10.3": "‘Ăn ếch, chuột ở sân phơi, ",
  "dn24:2.10.4": "Xác thối bị vứt ở nghĩa địa; ",
  "dn24:2.10.5": "Lớn lên trong đại rừng vắng, ",
  "dn24:2.10.6": "Chó rừng tưởng mình là sư tử vua loài thú; ",
  "dn24:2.10.7": "Và nó cứ kêu lên tiếng chó rừng, ",
  "dn24:2.10.8": "Chó rừng thấp hèn là gì, tiếng sư tử là gì. ",
  "dn24:2.10.9": "Cũng vậy, thưa tôn giả Pāthikaputta, ông sống nhờ uy đức của Đức Thiện Thệ, ăn thức ăn thừa của Đức Thiện Thệ, lại dám nghĩ đến việc xúc phạm Đức Như Lai, bậc A-la-hán, Chánh Đẳng Giác. ",
  "dn24:2.10.10": "Những kẻ như Pāthikaputta thấp hèn là gì, việc xúc phạm các Đức Như Lai, bậc A-la-hán, Chánh Đẳng Giác là gì.’ ",
  "dn24:2.11.1": "Khi Jāliya, đệ tử của Dārupattika, không thể dùng ví dụ này để khiến du sĩ lõa thể Pāthikaputta rời khỏi chỗ ngồi, này Bhaggava. ",
  "dn24:2.11.2": "Anh ấy trở về hội chúng và báo như vầy: ",
  "dn24:2.11.3": "‘Thưa các vị, du sĩ lõa thể Pāthikaputta đã thất bại rồi. Ông ta nói “Tôi đến, bạn, tôi đến, bạn” rồi vặn vẹo ngay tại chỗ, không thể đứng dậy khỏi ghế.’ ",
  "dn24:2.12.1": "Khi nghe vậy, này Bhaggava, Ta nói với hội chúng ấy: ",
  "dn24:2.12.2": "‘Thưa các vị, du sĩ lõa thể Pāthikaputta không thể đến gặp mặt Ta mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy. ",
  "dn24:2.12.3": "Dù ông ta có nghĩ rằng—",
  "dn24:2.12.4": "Ta sẽ đến gặp mặt Sa-môn Gotama mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy, thì đầu ông ta cũng sẽ vỡ ra. ",
  "dn24:2.12.5": "Dù quý vị Licchavi có nghĩ rằng—",
  "dn24:2.12.6": "chúng ta sẽ trói du sĩ lõa thể Pāthikaputta bằng dây da và dùng voi kéo đi, thì dây da sẽ đứt hoặc Pāthikaputta cũng sẽ vỡ ra. ",
  "dn24:2.12.7": "Nhưng du sĩ lõa thể Pāthikaputta không thể đến gặp mặt Ta mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy. ",
  "dn24:2.12.8": "Dù ông ta có nghĩ rằng—Ta sẽ đến gặp mặt Sa-môn Gotama mà không từ bỏ lời nói ấy, không từ bỏ tâm ấy, không xả bỏ tà kiến ấy, thì đầu ông ta cũng sẽ vỡ ra.’ ",
  "dn24:2.13.1": "Rồi, này Bhaggava, Ta chỉ dạy, khuyến khích, khích lệ, làm cho hội chúng ấy hoan hỷ bằng bài pháp; sau khi chỉ dạy, khuyến khích, khích lệ, làm cho hội chúng ấy hoan hỷ bằng bài pháp, Ta giải phóng họ khỏi sự trói buộc lớn, nâng đỡ tám mươi bốn ngàn chúng sinh khỏi hố nạn lớn, rồi nhập định hỏa giới, bay lên hư không bảy cây thốt nốt, tạo ra ngọn lửa cao bảy cây thốt nốt nữa, bốc cháy và phun khói, rồi xuất hiện lại tại giảng đường Kūṭāgāra trong Đại Lâm. ",
  "dn24:2.13.2": "Rồi, này Bhaggava, Sunakkhatta, con trai dòng Licchavi, đến chỗ Ta; đến nơi, đảnh lễ Ta rồi ngồi xuống một bên. Này Bhaggava, Ta nói với Sunakkhatta, con trai dòng Licchavi, đang ngồi một bên: ",
  "dn24:2.13.3": "‘Ngươi nghĩ sao, này Sunakkhatta, ",
  "dn24:2.13.4": "điều Ta đã tuyên bố về du sĩ lõa thể Pāthikaputta có xảy ra đúng như vậy không, hay khác đi?’ ",
  "dn24:2.13.5": "‘Bạch Thế Tôn, điều Đức Thế Tôn đã tuyên bố về du sĩ lõa thể Pāthikaputta đã xảy ra đúng như vậy, không khác.’ ",
  "dn24:2.13.6": "‘Ngươi nghĩ sao, này Sunakkhatta, ",
  "dn24:2.13.7": "nếu vậy, thần thông vượt quá pháp người thường có được biểu diễn hay không được biểu diễn?’ ",
  "dn24:2.13.8": "‘Bạch Thế Tôn, nếu vậy thần thông vượt quá pháp người thường đã được biểu diễn, chứ không phải không.’ ",
  "dn24:2.13.9": "‘Này kẻ ngu si, dù Ta đã biểu diễn thần thông vượt quá pháp người thường như vậy, ngươi lại nói với Ta—",
  "dn24:2.13.10": "Bạch Thế Tôn, nhưng Đức Thế Tôn không biểu diễn thần thông vượt quá pháp người thường cho con. ",
  "dn24:2.13.11": "Hãy xem, này kẻ ngu si, lỗi của ngươi lớn biết bao.’ ",
  "dn24:2.13.12": "Như vậy, này Bhaggava, dù được Ta nói, Sunakkhatta, con trai dòng Licchavi, vẫn từ bỏ Pháp và Luật này, như kẻ đã định đọa vào địa ngục. ",
  "dn24:2.14.0": "6. Câu Chuyện Về Nguồn Gốc Thế Giới ",
  "dn24:2.14.1": "Này Bhaggava, Ta biết rõ về nguồn gốc của thế giới. ",
  "dn24:2.14.2": "Ta biết điều đó, và biết điều vượt xa điều đó; biết mà không chấp trước, do không chấp trước, Niết Bàn được tự chứng ngộ nơi Ta, do biết rõ điều này, Đức Như Lai không rơi vào tai họa. ",
  "dn24:2.14.3": "Này Bhaggava, có một số Sa-môn, Bà-la-môn chủ trương rằng nguồn gốc thế giới là do Tự Tại Thiên tạo ra, do Phạm Thiên tạo ra. ",
  "dn24:2.14.4": "Ta đến gặp họ và hỏi: ",
  "dn24:2.14.5": "‘Có thật các tôn giả chủ trương rằng nguồn gốc thế giới là do Tự Tại Thiên tạo ra, do Phạm Thiên tạo ra không?’ ",
  "dn24:2.14.6": "Được hỏi như vậy, họ đáp ‘Vâng’. ",
  "dn24:2.14.7": "Ta nói với họ: ",
  "dn24:2.14.8": "‘Các tôn giả chủ trương như thế nào về nguồn gốc thế giới do Tự Tại Thiên tạo ra, do Phạm Thiên tạo ra?’ ",
  "dn24:2.14.9": "Được Ta hỏi, họ không trả lời được, không trả lời được, họ hỏi ngược lại Ta. ",
  "dn24:2.14.10": "Được hỏi, Ta trả lời họ: ",
  "dn24:2.14.11": "‘Thưa các tôn giả, có một thời kỳ mà sau một thời gian dài, thế giới này bị hoại diệt. ",
  "dn24:2.14.12": "Khi thế giới bị hoại diệt, phần lớn chúng sinh sinh vào cõi Quang Âm Thiên. ",
  "dn24:2.14.13": "Tại đó, họ là những chúng sinh do ý sinh, lấy hỷ làm thức ăn, tự mình phát hào quang, bay trên không trung, sống trong hạnh phúc, tồn tại rất lâu, rất lâu. ",
  "dn24:2.15.1": "Thưa các tôn giả, có một thời kỳ mà sau một thời gian dài, thế giới này được hình thành trở lại. ",
  "dn24:2.15.2": "Khi thế giới được hình thành, một cung điện Phạm thiên trống không xuất hiện. ",
  "dn24:2.15.3": "Rồi một chúng sinh nào đó, do hết tuổi thọ hoặc hết phước, từ cõi Quang Âm Thiên chết đi, tái sinh vào cung điện Phạm thiên trống không ấy. ",
  "dn24:2.15.4": "Tại đó, vị ấy là chúng sinh do ý sinh, lấy hỷ làm thức ăn, tự mình phát hào quang, bay trên không trung, sống trong hạnh phúc, tồn tại rất lâu, rất lâu. ",
  "dn24:2.16.1": "Do ở đó một mình trong thời gian dài, vị ấy sinh ra bất mãn và bồn chồn—",
  "dn24:2.16.2": "‘Ôi, mong sao các chúng sinh khác cũng đến sống nơi đây.’ ",
  "dn24:2.16.3": "Rồi các chúng sinh khác, do hết tuổi thọ hoặc hết phước, từ cõi Quang Âm Thiên chết đi, tái sinh vào cung điện Phạm thiên trống không ấy, làm bạn với chúng sinh đó. ",
  "dn24:2.16.4": "Họ cũng là những chúng sinh do ý sinh, lấy hỷ làm thức ăn, tự mình phát hào quang, bay trên không trung, sống trong hạnh phúc, tồn tại rất lâu, rất lâu. ",
  "dn24:2.17.1": "Thưa các tôn giả, chúng sinh nào đầu tiên tái sinh vào đó thì nghĩ như vầy—",
  "dn24:2.17.2": "ta là Phạm Thiên, Đại Phạm Thiên, bậc chinh phục, không ai chinh phục được, bậc thấy tất cả, bậc tự tại, đấng chủ tể, đấng sáng tạo, đấng hóa sinh, bậc tối thượng, đấng chỉ định, có quyền lực, cha của các loài đã sinh và sẽ sinh; các chúng sinh này do ta tạo ra. ",
  "dn24:2.17.3": "Vì sao vậy? ",
  "dn24:2.17.4": "Trước đây ta đã nghĩ—",
  "dn24:2.17.5": "‘Ôi, mong sao các chúng sinh khác cũng đến sống nơi đây’; ",
  "dn24:2.17.6": "và như vậy do nguyện lực của tâm ta, các chúng sinh này đã đến sống ở đây. ",
  "dn24:2.17.7": "Các chúng sinh sinh sau cũng nghĩ như vầy—",
  "dn24:2.17.8": "vị này là Phạm Thiên, Đại Phạm Thiên, bậc chinh phục, không ai chinh phục được, bậc thấy tất cả, bậc tự tại, đấng chủ tể, đấng sáng tạo, đấng hóa sinh, bậc tối thượng, đấng chỉ định, có quyền lực, cha của các loài đã sinh và sẽ sinh; ",
  "dn24:2.17.9": "chúng ta do vị Phạm Thiên này tạo ra. ",
  "dn24:2.17.10": "Vì sao vậy? ",
  "dn24:2.17.11": "Chúng ta đã thấy vị này tái sinh ở đây trước nhất; còn chúng ta tái sinh sau. ",
  "dn24:2.17.12": "Thưa các tôn giả, chúng sinh nào đầu tiên tái sinh vào đó có tuổi thọ dài hơn, dung sắc đẹp hơn, uy lực lớn hơn. ",
  "dn24:2.17.13": "Còn các chúng sinh sinh sau có tuổi thọ ngắn hơn, dung sắc xấu hơn, uy lực nhỏ hơn. ",
  "dn24:2.17.14": "Thưa các tôn giả, có khả năng một chúng sinh từ cõi ấy chết đi, tái sinh làm người. ",
  "dn24:2.17.15": "Sinh làm người, vị ấy từ bỏ gia đình, xuất gia sống không gia đình. ",
  "dn24:2.17.16": "Xuất gia sống không gia đình, nhờ tinh cần, nhờ chuyên chú, nhờ nhiệt tâm, nhờ không phóng dật, nhờ chánh tư niệm, vị ấy chạm đến tâm định đến mức nào đó, khi tâm đã định, vị ấy nhớ lại đời sống trước; quá đó thì không nhớ được. ",
  "dn24:2.17.17": "Vị ấy nói: ",
  "dn24:2.17.18": "“Vị Phạm Thiên, Đại Phạm Thiên ấy, bậc chinh phục, không ai chinh phục được, bậc thấy tất cả, bậc tự tại, đấng chủ tể, đấng sáng tạo, đấng hóa sinh, bậc tối thượng, đấng chỉ định, có quyền lực, cha của các loài đã sinh và sẽ sinh, vị Phạm Thiên đã tạo ra chúng ta. Vị ấy thường hằng, bền vững, vĩnh cửu, không thay đổi, sẽ tồn tại mãi mãi như vậy. ",
  "dn24:2.17.19": "Còn chúng ta do vị Phạm Thiên ấy tạo ra, chúng ta vô thường, không bền, tuổi thọ ngắn, chịu luật chết, và đã tái sinh làm người ở đây.” ",
  "dn24:2.17.20": "Chủ trương của các tôn giả về nguồn gốc thế giới do Tự Tại Thiên tạo ra, do Phạm Thiên tạo ra, có phải là như vậy chăng?’ ",
  "dn24:2.17.21": "Họ đáp: ",
  "dn24:2.17.22": "‘Thưa tôn giả Gotama, chúng tôi đã nghe nói như vậy, đúng như lời tôn giả Gotama nói.’ ",
  "dn24:2.17.23": "Này Bhaggava, Ta biết rõ về nguồn gốc của thế giới. ",
  "dn24:2.17.24": "Ta biết điều đó, và biết điều vượt xa điều đó; biết mà không chấp trước, do không chấp trước, Niết Bàn được tự chứng ngộ nơi Ta. Do biết rõ điều này, Đức Như Lai không rơi vào tai họa. ",
  "dn24:2.18.1": "Này Bhaggava, có một số Sa-môn, Bà-la-môn chủ trương rằng nguồn gốc thế giới là do chư thiên Khiḍḍāpadosika (Hý Tiếu Thiên). ",
  "dn24:2.18.2": "Ta đến gặp họ và hỏi: ",
  "dn24:2.18.3": "‘Có thật các tôn giả chủ trương rằng nguồn gốc thế giới là do chư thiên Khiḍḍāpadosika không?’ ",
  "dn24:2.18.4": "Được hỏi như vậy, họ đáp ‘Vâng’. ",
  "dn24:2.18.5": "Ta nói với họ: ",
  "dn24:2.18.6": "‘Các tôn giả chủ trương như thế nào về nguồn gốc thế giới do chư thiên Khiḍḍāpadosika?’ ",
  "dn24:2.18.7": "Được Ta hỏi, họ không trả lời được, không trả lời được, họ hỏi ngược lại Ta. ",
  "dn24:2.18.8": "Được hỏi, Ta trả lời họ: ",
  "dn24:2.18.9": "‘Thưa các tôn giả, có loại chư thiên gọi là Khiḍḍāpadosika. Họ sống quá mức trong sự cười đùa, vui chơi, hưởng thụ. Do sống quá mức trong sự cười đùa, vui chơi, hưởng thụ, họ bị mất chánh niệm, do mất chánh niệm họ chết từ cõi ấy. ",
  "dn24:2.18.10": "Thưa các tôn giả, có khả năng một chúng sinh từ cõi ấy chết đi, tái sinh làm người. ",
  "dn24:2.18.11": "Sinh làm người, vị ấy từ bỏ gia đình, xuất gia sống không gia đình. ",
  "dn24:2.18.12": "Xuất gia sống không gia đình, nhờ tinh cần, nhờ chuyên chú, nhờ nhiệt tâm, nhờ không phóng dật, nhờ chánh tư niệm, vị ấy chạm đến tâm định đến mức nào đó, khi tâm đã định, vị ấy nhớ lại đời sống trước; quá đó thì không nhớ được. ",
  "dn24:2.18.13": "Vị ấy nói: ",
  "dn24:2.18.14": "“Các vị thiên không phải Khiḍḍāpadosika thì không sống quá mức trong sự cười đùa, vui chơi, hưởng thụ. Do không sống quá mức trong sự cười đùa, vui chơi, hưởng thụ, họ không bị mất chánh niệm, do không mất chánh niệm họ không chết từ cõi ấy, ",
  "dn24:2.18.15": "thường hằng, bền vững, vĩnh cửu, không thay đổi, sẽ tồn tại mãi mãi như vậy. ",
  "dn24:2.18.16": "Còn chúng ta là Khiḍḍāpadosika, chúng ta đã sống quá mức trong sự cười đùa, vui chơi, hưởng thụ. Do chúng ta sống quá mức trong sự cười đùa, vui chơi, hưởng thụ, chúng ta bị mất chánh niệm, do mất chánh niệm chúng ta chết từ cõi ấy, ",
  "dn24:2.18.17": "vô thường, không bền, tuổi thọ ngắn, chịu luật chết, và đã tái sinh làm người ở đây.” ",
  "dn24:2.18.18": "Chủ trương của các tôn giả về nguồn gốc thế giới do chư thiên Khiḍḍāpadosika, có phải là như vậy chăng?’ ",
  "dn24:2.18.19": "Họ đáp: ",
  "dn24:2.18.20": "‘Thưa tôn giả Gotama, chúng tôi đã nghe nói như vậy, đúng như lời tôn giả Gotama nói.’ ",
  "dn24:2.18.21": "Này Bhaggava, Ta biết rõ về nguồn gốc của thế giới …nt… ",
  "dn24:2.18.22": "do biết rõ điều này, Đức Như Lai không rơi vào tai họa. ",
  "dn24:2.19.1": "Này Bhaggava, có một số Sa-môn, Bà-la-môn chủ trương rằng nguồn gốc thế giới là do chư thiên Manopadosika (Ý Phẫn Thiên). ",
  "dn24:2.19.2": "Ta đến gặp họ và hỏi: ",
  "dn24:2.19.3": "‘Có thật các tôn giả chủ trương rằng nguồn gốc thế giới là do chư thiên Manopadosika không?’ ",
  "dn24:2.19.4": "Được hỏi như vậy, họ đáp ‘Vâng’. ",
  "dn24:2.19.5": "Ta nói với họ: ",
  "dn24:2.19.6": "‘Các tôn giả chủ trương như thế nào về nguồn gốc thế giới do chư thiên Manopadosika?’ ",
  "dn24:2.19.7": "Được Ta hỏi, họ không trả lời được, không trả lời được, họ hỏi ngược lại Ta. ",
  "dn24:2.19.8": "Được hỏi, Ta trả lời họ: ",
  "dn24:2.19.9": "‘Thưa các tôn giả, có loại chư thiên gọi là Manopadosika. Họ nhìn nhau quá mức. Do nhìn nhau quá mức, tâm họ sinh sân hận với nhau. Có tâm sân hận với nhau, thân họ mệt mỏi, tâm họ mệt mỏi. Các vị thiên ấy chết từ cõi đó. ",
  "dn24:2.19.10": "Thưa các tôn giả, có khả năng một chúng sinh từ cõi ấy chết đi, tái sinh làm người. ",
  "dn24:2.19.11": "Sinh làm người, vị ấy từ bỏ gia đình, xuất gia sống không gia đình. ",
  "dn24:2.19.12": "Xuất gia sống không gia đình, nhờ tinh cần, nhờ chuyên chú, nhờ nhiệt tâm, nhờ không phóng dật, nhờ chánh tư niệm, vị ấy chạm đến tâm định đến mức nào đó, khi tâm đã định, vị ấy nhớ lại đời sống trước, quá đó thì không nhớ được. ",
  "dn24:2.19.13": "Vị ấy nói: ",
  "dn24:2.19.14": "“Các vị thiên không phải Manopadosika thì không nhìn nhau quá mức. Do không nhìn nhau quá mức, tâm họ không sinh sân hận với nhau. Không có tâm sân hận với nhau, thân họ không mệt mỏi, tâm họ không mệt mỏi. Các vị thiên ấy không chết từ cõi đó, ",
  "dn24:2.19.15": "thường hằng, bền vững, vĩnh cửu, không thay đổi, sẽ tồn tại mãi mãi như vậy. ",
  "dn24:2.19.16": "Còn chúng ta là Manopadosika, chúng ta đã nhìn nhau quá mức. Do chúng ta nhìn nhau quá mức, tâm chúng ta sinh sân hận với nhau. Có tâm sân hận với nhau, thân chúng ta mệt mỏi, tâm chúng ta mệt mỏi. Do vậy chúng ta đã chết từ cõi đó, ",
  "dn24:2.19.17": "vô thường, không bền, tuổi thọ ngắn, chịu luật chết, và đã tái sinh làm người ở đây.” ",
  "dn24:2.19.18": "Chủ trương của các tôn giả về nguồn gốc thế giới do chư thiên Manopadosika, có phải là như vậy chăng?’ ",
  "dn24:2.19.19": "Họ đáp: ",
  "dn24:2.19.20": "‘Thưa tôn giả Gotama, chúng tôi đã nghe nói như vậy, đúng như lời tôn giả Gotama nói.’ ",
  "dn24:2.19.21": "Này Bhaggava, Ta biết rõ về nguồn gốc của thế giới …nt… ",
  "dn24:2.19.22": "do biết rõ điều này, Đức Như Lai không rơi vào tai họa. ",
  "dn24:2.20.1": "Này Bhaggava, có một số Sa-môn, Bà-la-môn chủ trương rằng nguồn gốc thế giới là do ngẫu nhiên sinh khởi. ",
  "dn24:2.20.2": "Ta đến gặp họ và hỏi: ",
  "dn24:2.20.3": "‘Có thật các tôn giả chủ trương rằng nguồn gốc thế giới là do ngẫu nhiên sinh khởi không?’ ",
  "dn24:2.20.4": "Được hỏi như vậy, họ đáp ‘Vâng’. ",
  "dn24:2.20.5": "Ta nói với họ: ",
  "dn24:2.20.6": "‘Các tôn giả chủ trương như thế nào về nguồn gốc thế giới do ngẫu nhiên sinh khởi?’ ",
  "dn24:2.20.7": "Được Ta hỏi, họ không trả lời được, không trả lời được, họ hỏi ngược lại Ta. ",
  "dn24:2.20.8": "Được hỏi, Ta trả lời họ: ",
  "dn24:2.20.9": "‘Thưa các tôn giả, có loại chư thiên gọi là Vô Tưởng. ",
  "dn24:2.20.10": "Khi tưởng sinh khởi, các vị thiên ấy chết từ cõi đó. ",
  "dn24:2.20.11": "Thưa các tôn giả, có khả năng một chúng sinh từ cõi ấy chết đi, tái sinh làm người. ",
  "dn24:2.20.12": "Sinh làm người, vị ấy từ bỏ gia đình, xuất gia sống không gia đình. ",
  "dn24:2.20.13": "Xuất gia sống không gia đình, nhờ tinh cần, nhờ chuyên chú, nhờ nhiệt tâm, nhờ không phóng dật, nhờ chánh tư niệm, vị ấy chạm đến tâm định đến mức nào đó, khi tâm đã định, vị ấy nhớ lại sự sinh khởi của tưởng, quá đó thì không nhớ được.’ ",
  "dn24:2.20.14": "Vị ấy nói: ",
  "dn24:2.20.15": "‘Tự ngã và thế giới đều do ngẫu nhiên sinh khởi. ",
  "dn24:2.20.16": "Vì sao vậy? ",
  "dn24:2.20.17": "Trước kia ta không có, nay ta có, từ chỗ không có mà trở thành có.’ ",
  "dn24:2.20.18": "‘Chủ trương của các tôn giả về nguồn gốc thế giới do ngẫu nhiên sinh khởi, có phải là như vậy chăng?’ ",
  "dn24:2.20.19": "Họ đáp: ",
  "dn24:2.20.20": "‘Thưa tôn giả Gotama, chúng tôi đã nghe nói như vậy, đúng như lời tôn giả Gotama nói.’ ",
  "dn24:2.20.21": "Này Bhaggava, Ta biết rõ về nguồn gốc của thế giới; Ta biết điều đó, và biết điều vượt xa điều đó; biết mà không chấp trước, do không chấp trước, Niết Bàn được tự chứng ngộ nơi Ta. ",
  "dn24:2.20.22": "Do biết rõ điều này, Đức Như Lai không rơi vào tai họa. ",
  "dn24:2.21.1": "Này Bhaggava, dù Ta nói và tuyên bố như vậy, một số Sa-môn, Bà-la-môn vẫn vu khống Ta bằng những lời sai sự thật, trống rỗng, dối trá, không có thực: ",
  "dn24:2.21.2": "‘Sa-môn Gotama và các Tỳ Kheo là điên đảo. ",
  "dn24:2.21.3": "Sa-môn Gotama nói rằng—",
  "dn24:2.21.4": "khi chứng và trú trong giải thoát thanh tịnh, lúc ấy vị ấy chỉ nhận thức tất cả là bất tịnh.’ ",
  "dn24:2.21.5": "Nhưng này Bhaggava, Ta không nói như vậy: ",
  "dn24:2.21.6": "‘Khi chứng và trú trong giải thoát thanh tịnh, lúc ấy vị ấy chỉ nhận thức tất cả là bất tịnh.’ ",
  "dn24:2.21.7": "Mà này Bhaggava, Ta nói như vầy: ",
  "dn24:2.21.8": "‘Khi chứng và trú trong giải thoát thanh tịnh, lúc ấy vị ấy chỉ nhận thức là thanh tịnh.’” ",
  "dn24:2.21.9": "“Bạch Thế Tôn, những ai coi Đức Thế Tôn và các Tỳ Kheo là điên đảo, chính họ mới là điên đảo. ",
  "dn24:2.21.10": "Bạch Thế Tôn, con có niềm tin trọn vẹn nơi Đức Thế Tôn. Đức Thế Tôn có khả năng giảng Pháp cho con, để con có thể chứng và trú trong giải thoát thanh tịnh.” ",
  "dn24:2.21.11": "“Này Bhaggava, thật khó cho ngươi – người có tri kiến khác, có sở thích khác, có mong muốn khác, theo pháp môn khác, có thầy khác – để chứng và trú trong giải thoát thanh tịnh. ",
  "dn24:2.21.12": "Vậy thì, này Bhaggava, hãy khéo bảo vệ niềm tin mà ngươi đã có nơi Ta.” ",
  "dn24:2.21.13": "“Bạch Thế Tôn, nếu khó cho con – người có tri kiến khác, có sở thích khác, có mong muốn khác, theo pháp môn khác, có thầy khác – để chứng và trú trong giải thoát thanh tịnh, ",
  "dn24:2.21.14": "thì bạch Thế Tôn, con sẽ khéo bảo vệ niềm tin mà con đã có nơi Đức Thế Tôn.” ",
  "dn24:2.21.15": "Đức Thế Tôn đã nói như vậy. ",
  "dn24:2.21.16": "Du sĩ Bhaggavagotta hoan hỷ tín thọ lời dạy của Đức Thế Tôn. ",
  "dn24:2.21.17": "Kinh Pāthika đã kết thúc, là kinh thứ nhất. "
}

